    CONSTRAINT books_rating_check CHECK (((rating >= (0)::numeric) AND (rating <= (5)::numeric))),
    CONSTRAINT books_status_check CHECK ((status = ANY (ARRAY['reading'::text, 'queued'::text, 'completed'::text, 'paused'::text, 'dropped'::text])))
);


